class Playground {
    async run(inputs) {
        // 1. Array
        this.arr.init([5, 8, 3, 1]);
        this.arr.highlight(1, '#28d17c');

        // 2. Bar Array
        this.arr_bar.init([2, 5, 8, 4, 7]);
        this.arr_bar.highlight(2, '#28d17c');

        // 3. Stack
        this.stk.init([]);
        this.stk.push(10);
        this.stk.push(20);

        // 4. Queue
        this.que.init([]);
        this.que.enqueue(100);
        this.que.enqueue(200);

        // 5. Union Find
        this.uf.init(5);
        this.uf.union(0, 1);
        this.uf.union(1, 2);
        this.uf.highlightNode(0, '#a970ff');

        // 6. Graph
        this.gr.init([
            {id: 'A', val: 'A'}, {id: 'B', val: 'B'}, {id: 'C', val: 'C'}
        ], [
            {u: 'A', v: 'B', directed: false},
            {u: 'B', v: 'C', directed: false}
        ]);
        this.gr.highlightNode('A', '#00e0ff'); // Current
        this.gr.highlightNode('B', '#00f5a0'); // Visited
        this.gr.highlightNode('C', '#ffb703'); // Neighbor

        // 7. Trie
        this.tr.init();
        this.tr.insert('cat');
        this.tr.insert('car');
        this.tr.search('cat');

        this.log('All Data Structures initialized with their respective themes and highlights!');
        await this.await();
        return true;
    }
}
